import { describe, expect, it } from "vitest";
import { getTableConfig } from "drizzle-orm/pg-core";

import { signups } from "./signups.ts";

describe("signups schema", () => {
  const config = getTableConfig(signups);

  it("is named signups per the CTO spec", () => {
    expect(config.name).toBe("signups");
  });

  it("exposes id, email, source, created_at columns", () => {
    const names = config.columns.map((c) => c.name).sort();
    expect(names).toEqual([
      "created_at",
      "email",
      "id",
      "source",
    ]);
  });

  it("defaults source to 'landing-v1'", () => {
    const source = config.columns.find((c) => c.name === "source");
    expect(source?.default).toBe("landing-v1");
  });

  it("declares a unique constraint on (email)", () => {
    const u = config.uniqueConstraints.find(
      (x) => x.name === "signups_email_unique",
    );
    expect(u).toBeDefined();
    expect(u!.columns.map((c) => c.name)).toEqual(["email"]);
  });
});
